Map<String, String> parsePaxHeaders(final InputStream i) throws IOException {
    final Map<String, String> headers = new HashMap<>(globalPaxHeaders);

    // Format is "length keyword=value\n";
    while (true) { // Read length
        int ch = i.read();
        if (ch == -1) { // EOF
            break;
        }

        // Read the length of the header
        int len = 0;
        do {
            if (Character.isDigit(ch)) {
                len = len * 10 + (ch - '0');
            } else if (ch == ' ') {
                break; // End of length
            } else {
                throw new IOException("Invalid character in length: " + (char) ch);
            }
            ch = i.read();
            if (ch == -1) { // EOF check
                throw new IOException("Unexpected EOF while reading header length");
            }
        } while (true);

        // Get keyword
        final ByteArrayOutputStream coll = new ByteArrayOutputStream();
        while (true) {
            if (ch == '=') { // End of keyword
                final String keyword = coll.toString(CharsetNames.UTF_8);
                // Get rest of entry
                final int restLen = len - coll.size() - 1; // Subtract 1 for '='
                if (restLen == 0) { // Only NL (not including '=')
                    headers.remove(keyword);
                } else {
                    final byte[] rest = new byte[restLen];
                    int bytesRead = IOUtils.readFully(i, rest);
                    if (bytesRead != restLen) {
                        throw new IOException("Failed to read Paxheader. Expected "
                                              + restLen + " bytes, read "
                                              + bytesRead);
                    }
                    // Drop trailing NL if it exists
                    String value = new String(rest, 0, restLen - 1, CharsetNames.UTF_8);
                    headers.put(keyword, value);
                }
                break; // Processed single header
            } else if (ch == -1) { // EOF check
                throw new IOException("Unexpected EOF while reading keyword");
            } else {
                coll.write((byte) ch);
            }
            ch = i.read();
        }
    }
    return headers;
}
```

