```java
Map<String, String> parsePaxHeaders(final InputStream i) throws IOException {
    final Map<String, String> headers = new HashMap<>(globalPaxHeaders);

    while (true) { // Get length of header
        int ch;
        int len = 0;
        int read = 0;

        // Read the length of the header
        while ((ch = i.read()) != -1) {
            if (ch == ' ') {
                break; // Break on space to proceed to keyword
            }
            // Ensure len is only positive digits
            if (ch >= '0' && ch <= '9') {
                len = len * 10 + (ch - '0');
            } else {
                throw new IOException("Invalid header length: " + (char) ch);
            }
        }

        if (ch == -1) { // EOF
            break;
        }

        // Get keyword
        final ByteArrayOutputStream coll = new ByteArrayOutputStream();
        while ((ch = i.read()) != -1) {
            read++;
            if (ch == '=') { // end of keyword
                final String keyword = coll.toString(CharsetNames.UTF_8);

                // Read the rest of the entry
                final int restLen = len - read;
                if (restLen == 1) { // only NL
                    headers.remove(keyword);
                } else if (restLen > 1) {
                    final byte[] rest = new byte[restLen - 1]; // -1 to drop NL
                    final int got = IOUtils.readFully(i, rest);
                    if (got != restLen - 1) {
                        throw new IOException("Failed to read Paxheader. Expected "
                                              + (restLen - 1) + " bytes, read " + got);
                    }
                    // Store the value without the trailing NL
                    final String value = new String(rest, CharsetNames.UTF_8);
                    headers.put(keyword, value);
                }
                break; // Processed single header
            }
            coll.write((byte) ch);
        }
        if (ch == -1) { // EOF
            break;
        }
    }
    return headers;
}
```

